// ==========================================================================
// MÓDULO: Reporte de Notas por Materia (PDF)
// Genera un PDF que replica el formato oficial de la "Planilla de
// Calificaciones" de la escuela (ESET N°5 - Berazategui): encabezado
// institucional con logo, tabla de dos niveles (1º/2º Cuatrimestre) y 35
// filas fijas (cupo máximo real de un curso, entre regulares y recursantes).
//
// Columnas incluidas (solo las que la base de datos completa realmente):
//   Nº | Apellido y Nombre | 1º Valoración | Calif. 1º Cuat. (num) |
//   Intensificación 1°C (en blanco) | 2º Valoración | Calif. 2º Cuat. (num) |
//   Calificación Anual | Calificación Final
//
// Se excluyen a propósito (no están en la base): Cursa/Recursa, Inasistencias,
// Calificación Diciembre/Febrero y el bloque de estadísticas del pie.
//
// Requiere: jsPDF + jsPDF-AutoTable cargados antes de este script,
// y que exista window.supabaseCliente (conexion.js).
// ==========================================================================

const CUPO_MAXIMO_CURSO = 35; // Alumnos reales + recursantes, tope real de un curso

// Logo institucional incrustado en base64 (PNG), para no depender de rutas
// relativas ni de conexión a internet al generar el PDF.
const LOGO_ESCUELA_BASE64 = "data:image/png;base64,";

document.addEventListener("DOMContentLoaded", () => {
    const modalReporte = document.getElementById("modal-reporte-notas");
    const btnAbrir = document.getElementById("btn-abrir-reporte-notas");
    const btnCerrar = document.getElementById("btn-cerrar-modal-reporte");
    const selectCurso = document.getElementById("reporte-select-curso");
    const btnGenerar = document.getElementById("btn-generar-reporte");

    // Si el modal no está en la página (por ejemplo, en otra vista), no hacemos nada
    if (!btnAbrir || !modalReporte) return;

    btnAbrir.addEventListener("click", () => {
        modalReporte.classList.remove("oculto");
    });

    btnCerrar.addEventListener("click", () => {
        modalReporte.classList.add("oculto");
        resetearModalReporte();
    });

    selectCurso.addEventListener("change", cargarMateriasReporte);
    btnGenerar.addEventListener("click", generarReportePDF);
});

// Resetea los selects del modal a su estado inicial (al cerrar o luego de generar)
function resetearModalReporte() {
    const selectCurso = document.getElementById("reporte-select-curso");
    const selectMateria = document.getElementById("reporte-select-materia");
    if (selectCurso) selectCurso.value = "";
    if (selectMateria) {
        selectMateria.innerHTML = '<option value="">-- Seleccioná primero el curso --</option>';
        selectMateria.disabled = true;
    }
}

// Carga las materias del curso elegido en el selector de materia del modal
async function cargarMateriasReporte() {
    const curso = document.getElementById("reporte-select-curso").value;
    const selectMateria = document.getElementById("reporte-select-materia");

    if (!curso) {
        selectMateria.innerHTML = '<option value="">-- Seleccioná primero el curso --</option>';
        selectMateria.disabled = true;
        return;
    }

    selectMateria.innerHTML = '<option value="">Cargando materias...</option>';
    selectMateria.disabled = true;

    try {
        const { data: materias, error } = await window.supabaseCliente
            .from('materias')
            .select('id, nombre_materia')
            .eq('curso', curso)
            .order('nombre_materia');

        if (error) throw error;

        if (!materias || materias.length === 0) {
            selectMateria.innerHTML = '<option value="">-- No hay materias en este curso --</option>';
            return;
        }

        selectMateria.innerHTML = '<option value="">-- Elegir Materia --</option>' +
            materias.map(m => `<option value="${m.id}">${m.nombre_materia.toUpperCase()}</option>`).join('');
        selectMateria.disabled = false;

    } catch (err) {
        console.error("Error al cargar materias para el reporte:", err.message);
        selectMateria.innerHTML = '<option value="">-- Error al cargar --</option>';
    }
}

// Separa el nombre de curso (ej: "3ro 2da") en Año y Sección para el encabezado
function separarAnioSeccion(curso) {
    const partes = (curso || "").trim().split(/\s+/);
    return {
        anio: partes[0] || "",
        seccion: partes.slice(1).join(" ") || ""
    };
}

// Trae el listado combinado de alumnos: los regulares del curso + los que
// recursan esta materia puntual estando asignados a este curso (tabla recursadas).
// Se deduplican por id y se ordenan alfabéticamente por apellido.
async function obtenerListadoCompletoAlumnos(curso, nombreMateria) {
    const { data: alumnosReales, error: errReales } = await window.supabaseCliente
        .from('estudiantes')
        .select('id, nombre, apellido')
        .eq('curso_actual', curso);

    if (errReales) throw errReales;

    const { data: recursadasDelCurso, error: errRecursadas } = await window.supabaseCliente
        .from('recursadas')
        .select('estudiante_id')
        .eq('curso_recursada', curso)
        .ilike('materia', nombreMateria);

    if (errRecursadas) throw errRecursadas;

    let alumnosRecursantes = [];
    if (recursadasDelCurso && recursadasDelCurso.length > 0) {
        const idsRecursantes = [...new Set(recursadasDelCurso.map(r => r.estudiante_id))];
        const { data: datosRecursantes, error: errDatosRecursantes } = await window.supabaseCliente
            .from('estudiantes')
            .select('id, nombre, apellido')
            .in('id', idsRecursantes);

        if (errDatosRecursantes) throw errDatosRecursantes;
        alumnosRecursantes = datosRecursantes || [];
    }

    // Deduplicamos por id (por si un alumno figurara en ambas listas) y ordenamos
    const mapaAlumnos = new Map();
    [...(alumnosReales || []), ...alumnosRecursantes].forEach(a => mapaAlumnos.set(a.id, a));

    return Array.from(mapaAlumnos.values())
        .sort((a, b) => a.apellido.localeCompare(b.apellido, 'es'));
}

// Arma y genera el PDF con la planilla oficial de notas de la materia elegida
async function generarReportePDF() {
    const curso = document.getElementById("reporte-select-curso").value;
    const selectMateria = document.getElementById("reporte-select-materia");
    const materiaId = selectMateria.value;
    const nombreMateria = selectMateria.options[selectMateria.selectedIndex]?.text || "";

    if (!curso || !materiaId) {
        alert("Por favor, seleccioná un curso y una materia antes de generar el reporte.");
        return;
    }

    const btnGenerar = document.getElementById("btn-generar-reporte");
    const textoOriginal = btnGenerar.textContent;
    btnGenerar.textContent = "Generando PDF... ⏳";
    btnGenerar.disabled = true;

    try {
        // 1. Listado combinado: alumnos del curso + recursantes de esta materia en este curso
        const listadoCompleto = (await obtenerListadoCompletoAlumnos(curso, nombreMateria))
            .slice(0, CUPO_MAXIMO_CURSO);

        // 2. Notas de la materia para todos los alumnos de una sola vez
        const { data: boletines, error: errBoletines } = await window.supabaseCliente
            .from('boletines')
            .select('*')
            .eq('materia_id', parseInt(materiaId));

        if (errBoletines) throw errBoletines;

        const notasPorAlumno = {};
        (boletines || []).forEach(b => { notasPorAlumno[b.estudiante_id] = b; });

        // 3. Armamos exactamente CUPO_MAXIMO_CURSO filas: con datos si hay alumno
        //    en esa posición, o vacías (solo el número de orden) si no lo hay.
        const filas = [];
        for (let i = 0; i < CUPO_MAXIMO_CURSO; i++) {
            const alumno = listadoCompleto[i];
            if (!alumno) {
                filas.push([i + 1, "", "", "", "", "", "", "", ""]);
                continue;
            }
            const n = notasPorAlumno[alumno.id] || {};
            filas.push([
                i + 1,
                `${alumno.apellido.toUpperCase()}, ${alumno.nombre}`,
                n.primer_informe || "",
                n.primer_cuatrimestre ?? "",
                "", // Intensificación 1°C: no se registra en la base todavía
                n.segundo_informe || "",
                n.segundo_cuatrimestre ?? "",
                n.nota_anual ?? "",
                n.nota_final ?? ""
            ]);
        }

        // 4. Generamos el PDF con jsPDF + AutoTable, tamaño Legal vertical
        const { jsPDF } = window.jspdf;
        const doc = new jsPDF({ orientation: "portrait", unit: "mm", format: "legal" });
        const anioLectivo = new Date().getFullYear();
        const { anio, seccion } = separarAnioSeccion(curso);
        const anchoPagina = doc.internal.pageSize.getWidth();

        // --- Encabezado institucional (logo + nombre de la escuela) ---
        const logoTamanio = 18; // mm
        const logoX = 10;
        const logoY = 8;
        try {
            doc.addImage(LOGO_ESCUELA_BASE64, "PNG", logoX, logoY, logoTamanio, logoTamanio);
        } catch (errLogo) {
            console.warn("No se pudo insertar el logo en el PDF:", errLogo);
        }

        doc.setFont("helvetica", "bold");
        doc.setFontSize(12);
        doc.text("ESCUELA DE EDUCACIÓN SECUNDARIA TÉCNICA Nº 5 - BERAZATEGUI", anchoPagina / 2, 14, { align: "center" });

        doc.setFontSize(11);
        doc.text(`PLANILLA DE CALIFICACIONES ${anioLectivo}`, anchoPagina / 2, 20, { align: "center" });

        doc.setFont("helvetica", "normal");
        doc.setFontSize(9);
        doc.text(`MATERIA: ${nombreMateria}`, 10, 32);
        doc.text("DOCENTE: ______________________________________", 100, 32);
        doc.text(`AÑO: ${anio}     SECCIÓN: ${seccion}`, 10, 37);
        doc.text("TURNO: ____________     PRECEPTOR/A: ______________________________________", 60, 37);

        // --- Tabla principal (encabezado de dos niveles, igual al formulario oficial) ---
        doc.autoTable({
            startY: 42,
            head: [
                [
                    { content: "Nº", rowSpan: 2 },
                    { content: "Apellido y Nombre/s del/la Estudiante", rowSpan: 2 },
                    { content: "1º Cuatrimestre", colSpan: 2 },
                    { content: "2º Cuatrimestre", colSpan: 3 },
                    { content: "Calificación\nAnual", rowSpan: 2 },
                    { content: "Calificación\nFinal", rowSpan: 2 }
                ],
                [
                    "1º Valoración\n(TEA-TED-TEP)",
                    "Calificación 1º\nCuatrimestre (Num.)",
                    "Intensificación\n1° C",
                    "2º Valoración\n(TEA-TED-TEP)",
                    "Calificación 2º\nCuatrimestre (Num.)"
                ]
            ],
            body: filas,
            styles: { fontSize: 8, halign: "center", valign: "middle", lineColor: [15, 23, 42], lineWidth: 0.1 },
            headStyles: { fillColor: [15, 23, 42], textColor: 255, fontSize: 7.5, halign: "center", valign: "middle" },
            columnStyles: {
                0: { cellWidth: 8 },
                1: { cellWidth: 46, halign: "left" },
                2: { cellWidth: 20 },
                3: { cellWidth: 18 },
                4: { cellWidth: 18 },
                5: { cellWidth: 20 },
                6: { cellWidth: 18 },
                7: { cellWidth: 18 },
                8: { cellWidth: 18 }
            },
            margin: { left: 10, right: 10 }
        });

        // --- Firma del docente (debajo de la tabla, sin datos de la base) ---
        const finalY = doc.lastAutoTable.finalY;
        const alturaPagina = doc.internal.pageSize.getHeight();
        let posY = finalY + 15;
        if (posY > alturaPagina - 20) {
            doc.addPage();
            posY = 20;
        }
        doc.setFontSize(9);
        doc.text("______________________________________", anchoPagina / 2, posY, { align: "center" });
        doc.text("FIRMA DEL DOCENTE", anchoPagina / 2, posY + 5, { align: "center" });

        // 5. Mostramos el PDF en una pestaña nueva: el visor del navegador ya
        //    incluye botones para imprimir y descargar sin que tengamos que
        //    programar nada extra.
        const nombreArchivo = `Planilla_${curso}_${nombreMateria}.pdf`.replace(/\s+/g, "_");
        const blobUrl = doc.output("bloburl");
        const ventana = window.open(blobUrl, "_blank");

        if (!ventana) {
            // Si el navegador bloqueó la pestaña emergente, descargamos directo
            doc.save(nombreArchivo);
            alert("Tu navegador bloqueó la vista previa. El PDF se descargó directamente a tu equipo.");
        }

        document.getElementById("modal-reporte-notas").classList.add("oculto");
        resetearModalReporte();

    } catch (err) {
        console.error("Error al generar el reporte PDF:", err.message);
        alert("Ocurrió un error al generar el reporte. Verificá la conexión con Supabase.");
    } finally {
        btnGenerar.textContent = textoOriginal;
        btnGenerar.disabled = false;
    }
}
